        {
            MacroAccuracy = (float)bestMetrics.MacroAccuracy,
            MicroAccuracy = (float)bestMetrics.MicroAccuracy,
            LogLoss = (float)bestMetrics.LogLoss,
            LogLossReduction = (float)bestMetrics.LogLossReduction
        };

        // Train final model on all data
        ITransformer model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model
            .CreatePredictionEngine<TicketData, TicketPrediction>(model);

        // Extract category label ordering to map score indices to names
        var transformedData = model.Transform(dataView);
        var keyColumn = transformedData.Schema["Label"];
        VBuffer<ReadOnlyMemory<char>> keyValues = default;
        keyColumn.GetKeyValues(ref keyValues);
        _categoryLabels = keyValues.DenseValues().Select(v => v.ToString()).ToArray();
    }

